using System;
using System.Collections.Generic;
using System.Net.WebSockets;
using System.Text;
using System.Threading;
using System.Threading.Tasks;
using System.Web.Script.Serialization;
using GTA;

namespace ModProject
{
    public class Mod : Script
    {
        private const string WsUrl = "ws://127.0.0.1:60080";
        private const int RoseGiftId = 5655;
        private const int CooldownDurationMs = 30000;
        private const int MaxQueueSize = 100;
        private const int ReconnectDelayMs = 5000;

        private ClientWebSocket _ws;
        private CancellationTokenSource _cts;
        private readonly Queue<Action> _mainThreadActions = new Queue<Action>();
        private readonly object _queueLock = new object();
        private readonly JavaScriptSerializer _jsonSerializer = new JavaScriptSerializer();
        private int _cooldownUntil;

        public Mod()
        {
            this.Tick += OnTick;
            this.Interval = 0;
            _cooldownUntil = 0;
            _cts = new CancellationTokenSource();
            Task.Run(() => ConnectLoopAsync(_cts.Token));
        }

        private async Task ConnectLoopAsync(CancellationToken ct)
        {
            while (!ct.IsCancellationRequested)
            {
                try
                {
                    using (_ws = new ClientWebSocket())
                    {
                        await _ws.ConnectAsync(new Uri(WsUrl), ct);

                        string subJson = _jsonSerializer.Serialize(new
                        {
                            method = "serviceSignalSub",
                            @params = new { channel = "IM_MESSAGE_TRANSPORT" }
                        });
                        byte[] subBytes = Encoding.UTF8.GetBytes(subJson);
                        await _ws.SendAsync(
                            new ArraySegment<byte>(subBytes),
                            WebSocketMessageType.Text,
                            true,
                            ct);

                        await ReceiveLoopAsync(ct);
                    }
                }
                catch (Exception)
                {
                    // 连接失败或断开，等待后重连
                }

                try
                {
                    await Task.Delay(ReconnectDelayMs, ct);
                }
                catch (TaskCanceledException)
                {
                    break;
                }
            }
        }

        private async Task ReceiveLoopAsync(CancellationToken ct)
        {
            byte[] buffer = new byte[4096];
            StringBuilder sb = new StringBuilder();

            while (_ws.State == WebSocketState.Open && !ct.IsCancellationRequested)
            {
                WebSocketReceiveResult result;
                try
                {
                    result = await _ws.ReceiveAsync(new ArraySegment<byte>(buffer), ct);
                }
                catch (Exception)
                {
                    break;
                }

                if (result.MessageType == WebSocketMessageType.Close)
                    break;

                sb.Append(Encoding.UTF8.GetString(buffer, 0, result.Count));

                if (result.EndOfMessage)
                {
                    string msg = sb.ToString();
                    sb.Clear();
                    ProcessMessage(msg);
                }
            }
        }

        private void ProcessMessage(string json)
        {
            try
            {
                var dict = _jsonSerializer.Deserialize<Dictionary<string, object>>(json);
                if (dict == null) return;

                string msgType = null;
                if (dict.ContainsKey("method"))
                    msgType = dict["method"] as string;
                else if (dict.ContainsKey("type"))
                    msgType = dict["type"] as string;

                if (msgType == "WebcastGiftMessage")
                {
                    object payloadObj = null;
                    if (dict.ContainsKey("payload"))
                        payloadObj = dict["payload"];
                    else if (dict.ContainsKey("data"))
                        payloadObj = dict["data"];
                    else
                        payloadObj = dict;

                    var payload = payloadObj as Dictionary<string, object>;
                    if (payload == null) return;

                    int giftId = -1;
                    if (payload.ContainsKey("gift_id"))
                    {
                        object gid = payload["gift_id"];
                        if (gid is int)
                            giftId = (int)gid;
                        else if (gid != null)
                            int.TryParse(gid.ToString(), out giftId);
                    }

                    if (giftId == RoseGiftId)
                    {
                        int now = Environment.TickCount;
                        if (unchecked(now - _cooldownUntil) >= 0)
                        {
                            _cooldownUntil = unchecked(now + CooldownDurationMs);
                            EnqueueAction(ExecuteRoseEffects);
                        }
                    }
                }
            }
            catch (Exception)
            {
                // 消息解析失败，静默忽略
            }
        }

        private void EnqueueAction(Action action)
        {
            lock (_queueLock)
            {
                if (_mainThreadActions.Count < MaxQueueSize)
                    _mainThreadActions.Enqueue(action);
            }
        }

        private void OnTick(object sender, EventArgs e)
        {
            lock (_queueLock)
            {
                while (_mainThreadActions.Count > 0)
                {
                    Action action = _mainThreadActions.Dequeue();
                    try
                    {
                        action();
                    }
                    catch (Exception)
                    {
                        // 效果执行失败，继续处理下一个
                    }
                }
            }
        }

        private void ExecuteRoseEffects()
        {
            // 步骤A：设置天气为下雨
            try
            {
                Function.Call("SET_WEATHER_TYPE_NOW", "RAIN");
            }
            catch (Exception) { }

            // 步骤B：设置通缉等级为4星
            try
            {
                Function.Call("SET_PLAYER_WANTED_LEVEL", Game.Player, 4, false);
            }
            catch (Exception) { }

            // 步骤C：发放冲锋枪SMG及弹药
            try
            {
                Ped playerPed = Game.Player.Character;
                if (playerPed != null)
                {
                    Function.Call("GIVE_WEAPON_TO_PED", playerPed, (uint)WeaponHash.SMG, 9999, true, true);
                }
            }
            catch (Exception) { }
        }
    }
}
